import javax.jws.WebService;
import javax.jws.soap.SOAPBinding;
import javax.jws.WebMethod;
import javax.xml.soap.*;
import javax.xml.ws.Service;
import javax.xml.ws.soaps.SOAPBinding;

@WebService
@SOAPBinding(style = SOAPBinding.Style.RPC)
public class OrderProcessingService {
    
    @WebMethod
    public String processOrder(SOAPMessage request) {
        try {
            SOAPBody soapBody = request.getSOAPBody();
            SOAPElement orderElement = (SOAPElement) soapBody.getChildElements().next();
            NodeList items = orderElement.getElementsByTagName("item");
            double totalPrice = calculateTotalPrice(items);
            // Process order in your business logic
            // Place your order processing logic here
            return "Order processed successfully. Total price: " + totalPrice;
        } catch (SOAPException e) {
            e.printStackTrace();
            return "Error while processing order: " + e.getMessage();
        }
    }

    private double calculateTotalPrice(NodeList items) {
        double totalPrice = 0.0;
        for (int i = 0; i < items.getLength(); i++) {
            Node item = items.item(i);
            NodeList itemDetails = item.getChildNodes();
            double price = 0.0;
            int quantity = 0;
            for (int j = 0; j < itemDetails.getLength(); j++) {
                Node detail = itemDetails.item(j);
                if (detail.getNodeName().equals("price")) {
                    price = Double.parseDouble(detail.getTextContent());
                } else if (detail.getNodeName().equals("quantity")) {
                    quantity = Integer.parseInt(detail.getTextContent());
                }
            }
            totalPrice += price * quantity;
        }
        return totalPrice;
    }
}